module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    reg [7:0] SR; 
    reg [7:0] NEG_DIVISOR; 
    reg [3:0] cnt; 
    reg start_cnt; 
    reg [7:0] dividend_abs; 
    reg [7:0] divisor_abs; 
    reg carry_out; 
    reg [15:0] result_reg; 
    reg res_ready_reg; 

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dividend_abs <= 0;
            divisor_abs <= 0;
            SR <= 0;
            NEG_DIVISOR <= 0;
            cnt <= 0;
            start_cnt <= 0;
            res_valid <= 0;
            res_ready_reg <= 0;
        end
        else if (opn_valid && !res_valid) begin
            dividend_abs <= (sign && dividend[7]) ? ~dividend + 1 : dividend;
            divisor_abs <= (sign && divisor[7]) ? ~divisor + 1 : divisor;
            SR <= {dividend_abs, 1'b0};
            NEG_DIVISOR <= ~divisor_abs + 1;
            cnt <= 1;
            start_cnt <= 1;
        end
    end

    always @(posedge clk) begin
        if (start_cnt) begin
            if (cnt[3]) begin
                cnt <= 0;
                start_cnt <= 0;
                result_reg <= {SR[7:0], result_reg[15:8]};
            end
            else begin
                cnt <= cnt + 1;
                {carry_out, SR} <= {1'b0, SR} + {1'b0, NEG_DIVISOR};
                result_reg <= {result_reg[14:0], carry_out};
            end
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 0;
            res_ready_reg <= 0;
            result <= 0;
        end
        else begin
            if (cnt == 8) begin
                res_valid <= 1;
                res_ready_reg <= 0;
                result <= result_reg;
            end
            else if (res_valid && res_ready_reg) begin
                res_valid <= 0;
                res_ready_reg <= 0;
            end
            else begin
                res_valid <= res_valid;
                res_ready_reg <= res_ready;
            end
        end
    end
endmodule
